### 3. **Insecure Error Handling Exposes Sensitive Information**

**Location:** `exchangeCodeForTokens()`, `refreshTokens()`, retry logic  
**Risk:** MEDIUM - Information disclosure, credential leakage in logs

**Issue:** Error messages from Google OAuth API may contain sensitive information (partial tokens, client IDs, internal error details) that get propagated to application logs and potentially to end users.

**Recommended Fix:**
```typescript
/**
 * Custom error class for Gmail authentication failures
 */
export class GmailAuthError extends Error {
  constructor(
    message: string,
    public readonly code: string,
    public readonly recoverable: boolean = false
  ) {
    super(message);
    this.name = 'GmailAuthError';
  }
}

async exchangeCodeForTokens(code: string): Promise<OAuth2Tokens> {
  try {
    const { tokens } = await this.auth.getToken(code);
    const oauthTokens = tokens as OAuth2Tokens;
    await this.setTokens(oauthTokens);
    return oauthTokens;
  } catch (error) {
    // Sanitize error - don't expose Google's internal error details
    const sanitizedMessage = 'Failed to exchange authorization code for tokens. ' +
                            'The authorization code may be invalid or expired.';

    // Log full error internally for debugging (ensure logs are secure)
    console.error('[GmailClient] Token exchange failed:', {
      errorType: error instanceof Error ? error.name : 'Unknown',
      // Never log the actual code or error details to prevent token leakage
    });

    throw new GmailAuthError(
      sanitizedMessage,
      'TOKEN_EXCHANGE_FAILED',
      false // Not recoverable - requires new auth flow
    );
  }
}

async refreshTokens(): Promise<OAuth2Tokens> {
  try {
    const { credentials } = await this.auth.refreshAccessToken();
    const oauthTokens = credentials as OAuth2Tokens;
    await this.setTokens(oauthTokens);
    return oauthTokens;
  } catch (error) {
    const sanitizedMessage = 'Failed to refresh access token. ' +
                            'Re-authentication may be required.';

    console.error('[GmailClient] Token refresh failed:', {
      errorType: error instanceof Error ? error.name : 'Unknown',
      hasRefreshToken: !!this.auth.credentials.refresh_token,
    });

    throw new GmailAuthError(
      sanitizedMessage,
      'TOKEN_REFRESH_FAILED',
      false // Requires user interaction
    );
  }
}
```

