**Recommended Fix:**
```typescript
/**
 * Rate limiter to prevent quota exhaustion
 */
class RateLimiter {
  private requestCount = 0;
  private windowStart = Date.now();
  private readonly windowMs = 60000; // 1 minute
  private readonly maxRequestsPerWindow = 250; // Gmail API quota

  async checkRateLimit(): Promise<void> {
    const now = Date.now();

    // Reset window if expired
    if (now - this.windowStart > this.windowMs) {
      this.requestCount = 0;
      this.windowStart = now;
    }

    // Check if over quota
    if (this.requestCount >= this.maxRequestsPerWindow) {
      const waitTime = this.windowMs - (now - this.windowStart);
      console.warn(`[RateLimiter] Quota exceeded, waiting ${waitTime}ms`);
      await this.sleep(waitTime);
      this.requestCount = 0;
      this.windowStart = Date.now();
    }

    this.requestCount++;
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

export class GmailClient {
  private rateLimiter = new RateLimiter();

  private async executeWithRetry<T>(
    operation: () => Promise<T>, 
    options?: GmailRequestOptions
  ): Promise<T> {
    const maxRetries = options?.maxRetries ?? 3;
    const baseRetryDelayMs = options?.retryDelayMs ?? 1000;
    const retryOnRateLimit = options?.retryOnRateLimit ?? false;

    // Check rate limit BEFORE making request
    await this.rateLimiter.checkRateLimit();

    let lastError: Error | undefined;
    let attempt = 0;

    while (attempt <= maxRetries) {
      try {
        return await operation();
      } catch (error) {
        lastError = error as Error;
        attempt++;

        const apiError = error as { 
          code?: number; 
          errors?: Array<{ domain?: string; reason?: string }> 
        };

        // Check if this is a rate limit error
        const isRateLimitError =
          apiError.code === 429 ||
          apiError.errors?.some((e) => 
            e.domain === 'usageLimits' && e.reason === 'rateLimitExceeded'
          );

        // Only retry on rate limit errors if enabled
        if (!retryOnRateLimit || !isRateLimitError) {
          throw error;
        }

        // Don't retry if we've exhausted attempts
        if (attempt > maxRetries) {
          throw error;
        }

        // PROPER exponential backoff with jitter for production
        const exponentialDelay = baseRetryDelayMs * Math.pow(2, attempt - 1);
        const jitter = Math.random() * 1000; // 0-1000ms jitter
        const delay = exponentialDelay + jitter;

        console.warn(
          `[GmailClient] Rate limit hit, retry ${attempt}/${maxRetries} after ${delay.toFixed(0)}ms`
        );

        await this.sleep(delay);
      }
    }

    throw lastError;
  }
}
```

