ANOTHER_VAR=another_value
      `);

      loadEnvironment(cwd);

      expect(process.env.VALID_VAR).toBe('value');
      expect(process.env.ANOTHER_VAR).toBe('another_value');
    });

    it('should handle values with equals signs', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('CONNECTION_STRING=postgresql://user:pass@localhost/db?key=value\n');

