/**
 * Email Processor - Main Entry Point
 *
 * Direct Gmail API integration and email processing orchestration service.
 * Replaces n8n workflow infrastructure with simplified Node.js architecture.
 */

export * from './types';
export * from './gmail';
export * from './orchestrator';
export * from './persistence';
export * from './digest';

// Main email processing orchestrator
export { EmailProcessor } from './orchestrator';

// Gmail integration services
export { GmailClient, EmailFetcher } from './gmail';

// Database services
export { ConnectionPool, EmailRepository, ClassificationRepository } from './persistence';

// Digest generation services
export { TemplateEngine, DigestGenerator, EmailDelivery } from './digest';

