#!/usr/bin/env node
/**
 * Gmail OAuth2 Authorization CLI
 *
 * Interactive command-line tool to authorize Gmail API access and obtain
 * OAuth2 tokens (access token + refresh token).
 *
 * Usage:
 *   npm run authorize:gmail
 *   # or
 *   tsx src/cli/authorize-gmail.ts
 *
 * @packageDocumentation
 */

import * as readline from 'readline';
import * as fs from 'fs';
import * as path from 'path';
import { GmailClient } from '../gmail/gmail-client';
import { loadEnvironment } from '../config/env';

// Load environment variables
loadEnvironment();

/**
 * Prompt user for input via command line
 */
function prompt(question: string): Promise<string> {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });

  return new Promise((resolve) => {
    rl.question(question, (answer) => {
      rl.close();
      resolve(answer.trim());
    });
  });
}

/**
 * Save tokens to a JSON file for later use
 */
function saveTokens(tokens: Record<string, unknown>, outputPath: string): void {
  const tokensJson = JSON.stringify(tokens, null, 2);
  fs.writeFileSync(outputPath, tokensJson, 'utf-8');
  console.log(`\n✅ Tokens saved to: ${outputPath}`);
}

/**
 * Main authorization flow
 */
async function main() {
  console.log('==============================================');
  console.log('Gmail OAuth2 Authorization Tool');
  console.log('==============================================\n');

  // Check environment variables
  const clientId = process.env.GMAIL_CLIENT_ID;
  const clientSecret = process.env.GMAIL_CLIENT_SECRET;
  const redirectUri = process.env.GMAIL_REDIRECT_URI;

  if (!clientId || !clientSecret || !redirectUri) {
    console.error('❌ Error: Missing Gmail OAuth2 credentials in environment variables.\n');
    console.error('Please set the following in your .env file:');
    console.error('  - GMAIL_CLIENT_ID');
    console.error('  - GMAIL_CLIENT_SECRET');
    console.error('  - GMAIL_REDIRECT_URI\n');
    console.error('See ENVIRONMENT.md for setup instructions.');
    process.exit(1);
  }

  console.log('Environment variables loaded:');
  console.log(`  Client ID: ${clientId.substring(0, 20)}...`);
  console.log(`  Redirect URI: ${redirectUri}\n`);

  // Create Gmail client
  const client = new GmailClient({
    clientId,
    clientSecret,
    redirectUri,
  });

  // Step 1: Generate authorization URL
  console.log('Step 1: Generate Authorization URL\n');
  const authUrl = client.getAuthorizationUrl();

  console.log('📋 Copy and paste this URL into your browser:\n');
  console.log('─────────────────────────────────────────────');
  console.log(authUrl);
  console.log('─────────────────────────────────────────────\n');

  console.log("This will open Google's consent page where you can:");
  console.log('  1. Select which Google account to use');
  console.log('  2. Review the permissions being requested');
  console.log('  3. Grant access to your Gmail account\n');

  console.log('After granting access, Google will redirect to:');
  console.log(`  ${redirectUri}?code=AUTHORIZATION_CODE\n`);

  // Step 2: Wait for authorization code
  console.log('Step 2: Enter Authorization Code\n');

  const code = await prompt('Paste the authorization code here: ');

  if (!code) {
    console.error('\n❌ Error: No authorization code provided.');
    process.exit(1);
  }

  // Step 3: Exchange code for tokens
  console.log('\nStep 3: Exchange Code for Tokens\n');
  console.log('Exchanging authorization code for access and refresh tokens...');

  try {
    const tokens = await client.exchangeCodeForTokens(code);

    console.log('\n✅ Successfully obtained OAuth2 tokens!\n');
    console.log('Token details:');
    console.log(`  Access Token: ${tokens.access_token?.substring(0, 20)}...`);
    console.log(
      `  Refresh Token: ${tokens.refresh_token ? tokens.refresh_token.substring(0, 20) + '...' : 'Not provided'}`
    );
    console.log(`  Expires: ${tokens.expiry_date ? new Date(tokens.expiry_date).toISOString() : 'Unknown'}\n`);

    // Step 4: Verify tokens work
    console.log('Step 4: Verify Tokens\n');
    console.log('Testing tokens by fetching your Gmail profile...');

    const profile = await client.getUserProfile();

    console.log('\n✅ Tokens verified! Successfully connected to Gmail.\n');
    console.log('Gmail account details:');
    console.log(`  Email: ${profile.emailAddress}`);
    console.log(`  Total messages: ${profile.messagesTotal}`);
    console.log(`  Total threads: ${profile.threadsTotal}\n`);

    // Step 5: Save tokens
    console.log('Step 5: Save Tokens\n');

    const defaultPath = path.join(process.cwd(), 'gmail-tokens.json');
    const savePath = await prompt(`Save tokens to file? [${defaultPath}] (press Enter for default, or specify path): `);
    const outputPath = savePath || defaultPath;

    saveTokens(tokens, outputPath);

    console.log('\n⚠️  SECURITY WARNING:');
    console.log('   The tokens file contains sensitive credentials.');
    console.log('   - Do NOT commit gmail-tokens.json to version control');
    console.log('   - Store securely (encrypted storage, secrets manager)');
    console.log('   - Add to .gitignore if not already included\n');

    console.log('Next steps:');
    console.log('  1. Use these tokens to initialize GmailClient:');
    console.log('     ```typescript');
    console.log('     const tokens = JSON.parse(fs.readFileSync("gmail-tokens.json"));');
    console.log('     await gmailClient.setTokens(tokens);');
    console.log('     ```\n');
    console.log('  2. The refresh token can be used to obtain new access tokens');
    console.log('     when the current one expires (typically after 1 hour).\n');

    console.log('==============================================');
    console.log('Authorization Complete! 🎉');
    console.log('==============================================\n');
